/** Route form chứng từ / full-page có shell scroll nội bộ (§8.10.2). */
export function isVoucherFormPath(pathname: string): boolean {
  const parts = pathname.split('/').filter(Boolean);
  if (parts.length < 3 || parts[0] !== 'sx') return false;
  const [, module, action] = parts;
  if (module === 'lsx' || module === 'bom') {
    return action === 'them' || (action.length > 0 && action !== 'them');
  }
  return false;
}
